mapper.select:
/** CmmtQnaAnswererDao.select */
select

from cmmt_qna_answerer a
where
	qna_id = #{qnaId}
	and member_id = #{memberId}

/** CmmtQnaAnswererDao.selectList */ select
from cmmt_qna_answerer a where qna_id = #{qnaId}
and member_id in (select member_id from cmmt_member where member_nm = #{memberNm})
and member_id in (select member_id from cmmt_member where login_id = #{loginId})

mapper.insert:
/** CmmtQnaAnswererDao.insert */
insert into cmmt_qna_answerer (
	 qna_id
	,member_id
	,creator_id
	,created_dt
) values (
	 #{qnaId}
	,#{memberId}
	,#{creatorId}
	,#{createdDt}
)

/** CmmtQnaAnswererDao.insertList */
insert into cmmt_qna_answerer (
	 qna_id
	,member_id
	,creator_id
	,created_dt
) values

	(
		 #{item.qnaId}
		,#{item.memberId}
		,#{item.creatorId}
		,#{item.createdDt}
	)

mapper.delete:
